UPDATE board_article
SET subject = #{subject}, content = #{content}, subject_eng = #{subjectEng}, content_eng = #{contentEng}, date_modified = now(), user_id_modified = #{userIdModified}, open_yn = #{openYn}
, board_idx = #{boardIdx}
WHERE board_article_idx = #{boardArticleIdx}

UPDATE board_article
SET hit_count = hit_count + 1
WHERE board_article_idx = #{boardArticleIdx}

UPDATE board_article
SET date_modified = now(), user_id_modified = #{userIdModified}, delete_yn = 'Y'
WHERE board_article_idx = #{boardArticleIdx}
